HonourConfig = {}
HonourConfig.honour = {}

function HonourConfig:init(config)
    for i, v in pairs(config) do
        local data = {}
        data.id = tonumber(v.id)
        data.rank = tonumber(v.rank)
        data.integral = tonumber(v.integral)
        self.honour[i] = data
    end
end

function HonourConfig:getHonourByRank(rank)
    for _, k in pairs(self.honour) do
        if k.rank == rank then
            return k.integral
        end
    end
    return 0
end

return HonourConfig